import React, { useState } from 'react'
import { Canvas, useLoader } from '@react-three/fiber' // <--- Move useLoader here
import { Float, OrbitControls, Text } from '@react-three/drei' // <--- Remove it from here
import { TextureLoader } from 'three'
import confetti from 'canvas-confetti'

const EnvelopeCube = () => {
  const [isOpen, setIsOpen] = useState(false)
  const textures = useLoader(TextureLoader, [
    '/assets/eid1.jpeg', '/assets/eid2.jpg', '/assets/eid3.jpg', 
    '/assets/eid4.jpg', '/assets/eid5.jpg', '/assets/eid6.jpg'
  ])

  const handleClick = () => {
    setIsOpen(!isOpen)
    if (!isOpen) confetti({ particleCount: 100, spread: 70, origin: { y: 0.6 } })
  }

  return (
    <group onClick={handleClick} scale={0.6}>
      {/* Mesh 1: Attach materials to faces 0, 1, 2 */}
      <mesh position={[isOpen ? -1.5 : 0, 0, 0]}>
        <boxGeometry args={[1.5, 1.5, 1.5]} />
        {textures.map((tex, i) => (
          <meshStandardMaterial key={i} attach={`material-${i}`} map={tex} />
        ))}
      </mesh>

      {/* Mesh 2: Attach materials to faces 3, 4, 5 */}
      {/* Note: If you want to use the same textures, just map them again or pick specific ones */}
      <mesh position={[isOpen ? 1.5 : 0, 0, 0]}>
        <boxGeometry args={[1.5, 1.5, 1.5]} />
        {textures.map((tex, i) => (
          <meshStandardMaterial key={i} attach={`material-${i}`} map={tex} />
        ))}
      </mesh>

      {isOpen && (
        <Float speed={2} floatIntensity={2}>
          <Text position={[0, 2, 0]} color="gold" fontSize={0.8}>
            Eid Mubarak!
          </Text>
        </Float>
      )}
    </group>
  )
}
export default function App() {
  return (
    <Canvas style={{ height: '100vh', background: '#0a192f' }}>
      <ambientLight intensity={0.8} />
      <EnvelopeCube />
      <OrbitControls />
    </Canvas>
  )
}
